VALUES
  ('social-worker-moex-06000', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '老年階段是由許多「失落」編織而成，下列何者並非學者 William Worden（2001）所提出哀悼失落必須 完成的任務？', '["找到和往生者維持連結的適當方式", "接受失落", "適應往生者永不復返的情境", "迴避痛苦的感受"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06001', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「當兒童有不當行為時，父母以口頭貶抑、威脅要將其送走，以及指出對方的不當行為是造成不再被愛 的原因」，這是下列那種父母管教的策略？', '["循循誘導（induction）", "民主管教（democracy discipline）", "愛的暫撤（love withdraw）", "威權管教（power assertive discipline）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06002', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關Piaget「認知發展理論」之敘述，何者錯誤？', '["「能塗鴉，投射以代表某些人事物」是處於前運思期（preoperational stage）的兒童，所表現出來的特 徵之一", "這個理論對於兒童福利服務領域之實務工作者，在評量問題與選擇適當的處遇模式上，都有重大的影響", "前運思期又可以細分成「象徵功能」與「直覺思考」兩個次階段", "「學習與適應」是該理論主要的概念"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06003', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關「主觀的同性戀恐懼症」的敘述，何者錯誤？', '["係指同性戀者，感知到部分社會大眾對他們的偏執與厭惡，而產生的一種強烈的自我厭惡感", "係指部分社會大眾對於同性戀者，所產生種種不理性的主觀態度", "主觀的同性戀恐懼症，將嚴重影響同性戀者與他人建立親密關係的能力", "良好的社會支持網絡，將能協助同性戀者降低主觀的同性戀恐懼症"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06004', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「同時擁有傳統上女性陰柔的特質與男性陽剛的特質」的概念，下列何者錯誤？', '["這是「雙性化人格」的觀點", "不要強調男性一定得成為主宰及成功的領導者時，則可降低中年危機的產生", "強調男性與女性特質互換，代表著男人要像女人、女人要像男人", "不論何種性別，每個人都應該被允許自由活出自己想過的生活"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06005', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對「性別角色的刻板印象」之敘述，何者錯誤？', '["性別角色的刻板印象不允許個體之間有差異產生，產生差異的個體容易成為被攻擊或歧視的對象", "性別角色的刻板印象對於不同性別的個體，都會產生許多的束縛與壓力", "性別角色的刻板印象是可以被改變的", "不同性別的刻板印象，在不同文化脈絡下，幾乎大同小異"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06006', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關高齡懷孕的敘述，何者錯誤？', '["若是超過35歲以上才懷孕，不論對母親或是孩子而言，都是百害而無一利", "相較於20多歲懷孕的女性，年長女性在懷孕階段，出現妊娠高血壓和糖尿病的機率是比較高的", "高齡懷孕的流產機率，相較於年輕懷孕的女性，是比較高的", "年長的女性，由於經濟條件較為穩定，對於擔任母親的角色，是更有自信的"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06007', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關父母離婚對學齡前期幼兒影響之敘述，何者錯誤？', '["處於學齡前期的幼兒，比年紀大的兒童，更容易在情緒及心理上，受到父母離婚的影響", "這個階段的幼兒，若無法適應父母離婚的狀態，則這種不適應的情況，是永久不變的", "學齡前期的幼兒，難以理解父母離婚的意義，他們認為永遠無法與因為離婚而離家的父或母見面，而 心生焦慮", "由於學齡前期的幼兒的「自我中心」，他們認為父母離婚是自己行為所造成的，而產生自責的情緒"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06008', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關嬰幼兒特質的敘述，何者錯誤？', '["一般而言，1歲嬰幼兒的體重，大約是剛出生時的3倍左右", "約4個月大的嬰幼兒，眼睛所見的事物與成年人相同，但並沒有與成年人對於該項事物，有相同的認知", "嬰幼兒的聽覺，在子宮內便已經開始發展，且他們出生後，對於母親的聲音偏好，勝於其他女性", "嬰幼兒的體型，與營養、疾病、環境因素等，有重要相關，和遺傳則無太大關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06009', 'social-worker', 'social-worker-moex-104-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關成年前期的敘述，何者錯誤？', '["這個階段的成年人需要發展出與他人情感連結的新方法，同時又得保住自己的個體性", "依據Erikson的心理社會理論，這個階段的發展任務與發展危機，是「親密V.S.混淆」", "有一份穩定的工作，能為這個階段的成年人，增加自我認同與社會支持", "這個階段的成年人若已成家，他與伴侶之間之親職、家務分工，是影響其婚姻滿意度的重要因素之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "e940395bf645", "answer_pdf_sha1": "65c26ed049a7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
